import React from 'react';

function App() {
  return (
    <div style={{ 
      padding: '20px', 
      fontFamily: 'Arial, sans-serif',
      maxWidth: '1200px',
      margin: '0 auto'
    }}>
      <h1 style={{ color: '#2563eb' }}>📚 Library Management System</h1>
      <p>Bienvenue dans l'application de gestion de bibliothèque</p>

      <div style={{ 
        marginTop: '20px',
        padding: '20px',
        backgroundColor: '#f3f4f6',
        borderRadius: '8px'
      }}>
        <h2>État du système</h2>
        <p>✅ Frontend: http://localhost:3000</p>
        <p id="backend-status">⏳ Vérification du backend...</p>
      </div>

      <div style={{ marginTop: '30px' }}>
        <h2>Navigation</h2>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button style={buttonStyle}>Accueil</button>
          <button style={buttonStyle}>Livres</button>
          <button style={buttonStyle}>Connexion</button>
        </div>
      </div>
    </div>
  );
}

const buttonStyle = {
  padding: '10px 20px',
  backgroundColor: '#2563eb',
  color: 'white',
  border: 'none',
  borderRadius: '5px',
  cursor: 'pointer',
  fontSize: '16px'
};

export default App;
